class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        count = 0
        for c in 'abcdefghijklmnopqrstuvwxyz':
            positions_lower = [i for i, ch in enumerate(word) if ch == c]
            positions_upper = [i for i, ch in enumerate(word) if ch == c.upper()]
            if positions_lower and positions_upper and max(positions_lower) < min(positions_upper):
                count += 1
        return count

