class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        last_lower = {}
        first_upper = {}
        for i, c in enumerate(word):
            if c.islower():
                last_lower[c] = i
            else:
                key = c.lower()
                if key not in first_upper:
                    first_upper[key] = i
        count = 0
        for c in last_lower:
            if c in first_upper and last_lower[c] < first_upper[c]:
                count += 1
        return count

