var numberOfSpecialChars = function(word) {
    const lastLower = {};
    const firstUpper = {};
    for (let i = 0; i < word.length; i++) {
        const c = word[i];
        if (c >= 'a' && c <= 'z') {
            lastLower[c] = i;
        } else {
            const key = c.toLowerCase();
            if (!(key in firstUpper)) firstUpper[key] = i;
        }
    }
    let count = 0;
    for (const c in lastLower) {
        if (c in firstUpper && lastLower[c] < firstUpper[c]) count++;
    }
    return count;
};
